    if (!head) {
        head = newNode;
        return head;
    }
    let temp = head;
    while (temp.next) {
        temp = temp.next;
    }
    temp.next = newNode;
    return head;
}

// Utility function to check presence of intersection
function intersectionPresent(head1, head2) {
    let d1 = head1, d2 = head2;
    // Traverse both lists, when one reaches the end, redirect it to the head of the other list
    while (d1 !== d2) {
        d1 = d1 === null ? head2 : d1.next;
        d2 = d2 === null ? head1 : d2.next;
    }
    return d1;  // If they meet, return the intersection node, otherwise null
}

// Utility function to print linked list
function printList(head) {
    while (head && head.next) {
        process.stdout.write(`${head.num}->`);
        head = head.next;
    }
    if (head) {
        process.stdout.write(`${head.num}`);
    }
    console.log();
}

// Driver code
let head = new Node(1);
insertNode(head, 3);
insertNode(head, 1);
insertNode(head, 2);
insertNode(head, 4);
let head1 = head;
head = head.next.next.next;  // Intersection point
let headSec = new Node(3);
let head2 = headSec;
headSec.next = head;  // Creating intersection

// Printing the lists
console.log("List1: ");
printList(head1);
console.log("List2: ");
printList(head2);

// Checking if intersection is present
let answerNode = intersectionPresent(head1, head2);
if (answerNode === null) {
    console.log("No intersection");
} else {
    console.log(`The intersection point is ${answerNode.num}`);
}
